<?php namespace App\Http\Responses; use Illuminate\Http\Resources\Json\JsonResource; class ApiResponseSchema extends JsonResource { protected $status; protected $message; protected $errors; protected $meta; public function __construct($resource, $status = 'success', $message = null, $errors = null, $meta = []) { parent::__construct($resource); $this->status = $status; $this->message = $message; $this->errors = $errors; $this->meta = $meta; } public function toArray($request) { return [ 'status' => $this->status, 'message' => $this->message, 'data' => $this->resource, 'errors' => $this->errors, 'meta' => $this->meta, ]; } public static function success($data, $message = 'تمت العملية بنجاح', $code = 200) { return (new self($data, 'success', $message))->response()->setStatusCode($code); } public static function error($message = 'حدث خطأ غير متوقع', $errors = null, $code = 400) { return (new self(null, 'error', $message, $errors))->response()->setStatusCode($code); } public static function warning($data, $message = 'تحذير', $code = 200) { return (new self($data, 'warning', $message))->response()->setStatusCode($code); } }